INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 1, 3, 'grammar', '{"intro": {"ja": "複数の助詞を組み合わせて、より複雑な文を作ります。「だれが何をいつするのか」という基本的な質問の文法を学びます。介護の現場では、患者さんの状態や行動を正確に説明する時に重要です。", "vi": "Kết hợp nhiều trợ từ để tạo câu phức tạp hơn. Học ngữ pháp câu hỏi cơ bản \"ai làm cái gì lúc mấy giờ\". Trong chăm sóc, quan trọng để mô tả chính xác tình trạng hoặc hành động của bệnh nhân."}, "patterns": [{"pattern": "助詞の組み合わせ：N1は N2が V", "meaning": {"ja": "主体と行動を同時に表す。主語の中に目的語がある場合の文法", "vi": "Biểu hiện cả chủ thể và hành động cùng một lúc. Ngữ pháp khi câu ngang một chủ thể chứa tân ngữ"}, "examples": [{"ja": "私は手が痛いです。", "vi": "Tôi có cơn đau tay (bàn tay của tôi đau)."},{"ja": "患者さんは足が腫れています。", "vi": "Bệnh nhân có phù nề ở chân."}], "care_context": "患者さんの症状を説明する時：「患者さんは腰が痛いです」「頭が重いです」", "explanation": {"ja": "は と が を同時に使う時、は全体を示し、が詳細な行動や状態を示します。", "vi": "Khi sử dụng は và が cùng lúc, は chỉ toàn bộ, が chỉ hành động hoặc trạng thái chi tiết."}, "difficulty": "medium"}, {"pattern": "質問文：N は V ますか？", "meaning": {"ja": "はい/いいえで答える質問の形。敬語版", "vi": "Dạng câu hỏi được trả lời bằng có/không. Phiên bản lịch sự"}, "examples": [{"ja": "今日、来ますか？", "vi": "Hôm nay bạn đến không?"},{"ja": "薬を飲みましたか？", "vi": "Bạn uống thuốc chưa?"}], "care_context": "患者さんに日々の行動や状態を確認する時：「昨晩、よく寝ましたか？」「朝食を食べましたか？」", "explanation": {"ja": "ますか？という形は敬語の質問文です。患者さんとの会話では常に使う重要な表現です。", "vi": "Dạng ますか là câu hỏi lịch sự. Biểu hiện quan trọng được sử dụng thường xuyên khi nói chuyện với bệnh nhân."}, "difficulty": "easy"}, {"pattern": "N1は N2と V ます", "meaning": {"ja": "だれかと一緒に何かをする", "vi": "Làm cái gì cùng với ai"}, "examples": [{"ja": "看護師と一緒に歩きます。", "vi": "Tôi đi bộ cùng với y tá."},{"ja": "家族と一緒に食事をします。", "vi": "Tôi ăn cơm cùng với gia đình."}], "care_context": "患者さんが他の人と何かをする場合：「スタッフと一緒に入浴します」「友達と一緒に散歩します」", "explanation": {"ja": "と は「〜と一緒に」という意味で使います。相互行動を示します。", "vi": "Trợ từ と được sử dụng với nghĩa \"cùng với\". Biểu hiện hành động tương互tác."}, "difficulty": "medium"}], "dialogue": ["患者さん: 「昨日、よく寝ましたか？」", "介護職: 「はい、よく寝ました。ありがとうございます。」", "患者さん: 「今日は誰と一緒に散歩しますか？」", "介護職: 「田中さんと一緒に散歩します。」", "患者さん: 「そうですか。いいですね。」", "介護職: 「患者さんも一緒に散歩しませんか？」", "患者さん: 「いいですね。散歩に行きましょう。」"], "key_phrases": [{"ja": "～は～が", "vi": "~は~が"},{"ja": "～ますか？", "vi": "~ますか？"},{"ja": "～と一緒に", "vi": "~cùng với"},{"ja": "～ましたか？", "vi": "~ましたか？"}], "cultural_note": {"ja": "複合助詞の使い分けは、正確で自然な日本語表現の鍵です。介護現場では、患者さんの状態や行動を正確に理解し、説明することが信頼構築の基本です。", "vi": "Phân biệt sử dụng trợ từ kết hợp là chìa khóa của biểu hiện tiếng Nhật chính xác và tự nhiên. Trong chăm sóc, hiểu và giải thích chính xác tình trạng và hành động của bệnh nhân là cơ sở xây dựng lòng tin."}, "quiz": [{"question": {"ja": "「患者さんは足が腫れています」の意味は？", "vi": "Ý nghĩa của \"患者さんは足が腫れています\" là gì?"}, "options": [{"ja": "患者さんが足を見ている", "vi": "Bệnh nhân đang nhìn chân"},{"ja": "患者さんの足が腫れている状態", "vi": "Chân bệnh nhân đang sưng phù"},{"ja": "患者さんの足は見えない", "vi": "Chân bệnh nhân không nhìn thấy"},{"ja": "患者さんが足を動かしている", "vi": "Bệnh nhân đang cử động chân"}], "correct_answer": 1, "explanation": {"ja": "は と が を同時に使う時、患者さんの足が腫れている状態を示します。", "vi": "Khi sử dụng は と が cùng lúc, nó biểu hiện tình trạng chân bệnh nhân sưng phù."}, "difficulty": "easy"}, {"question": {"ja": "「来ますか？」の使い方は？", "vi": "Cách sử dụng \"来ますか？\" là?"}, "options": [{"ja": "陳述である", "vi": "Là một tuyên bố"},{"ja": "礼儀正しい質問である", "vi": "Là câu hỏi lịch sự"},{"ja": "命令である", "vi": "Là một mệnh lệnh"},{"ja": "過去について話している", "vi": "Nói về quá khứ"}], "correct_answer": 1, "explanation": {"ja": "ますか？という形は敬語の質問形式です。患者さんとの会話に適切です。", "vi": "Dạng ますか là hình thức câu hỏi lịch sự. Thích hợp cho cuộc hội thoại với bệnh nhân."}, "difficulty": "easy"}, {"question": {"ja": "「スタッフと一緒に歩く」の意味は？", "vi": "Ý nghĩa của \"スタッフと一緒に歩く\" là?"}, "options": [{"ja": "スタッフが一人で歩く", "vi": "Nhân viên đi bộ một mình"},{"ja": "スタッフと患者さんが一緒に歩く", "vi": "Nhân viên và bệnh nhân đi bộ cùng nhau"},{"ja": "患者さんが一人で歩く", "vi": "Bệnh nhân đi bộ một mình"},{"ja": "スタッフが患者さんを見ている", "vi": "Nhân viên đang quan sát bệnh nhân"}], "correct_answer": 1, "explanation": {"ja": "「と一緒に」は「一緒に」という意味で、複数の人が一緒に行動することを示します。", "vi": "\"と一緒に\" có nghĩa là làm cùng với ai, biểu hiện nhiều người hành động cùng nhau."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 2, 3, 'grammar', '{"intro": {"ja": "「もし～たら」「～ば」など、条件を表す表現を学びます。「もし痛かったら、教えてください」など、患者さんへの配慮や指示を与える時に必要な文法です。", "vi": "Học những biểu hiện để nói điều kiện như \"もし～たら\" \"～ば\". \"Nếu đau, vui lòng cho tôi biết\"... Ngữ pháp cần thiết khi chỉ dạn hoặc quan tâm đến bệnh nhân."}, "patterns": [{"pattern": "もし～たら、～", "meaning": {"ja": "条件：～だったら～", "vi": "Điều kiện: nếu ~thì ~"}, "examples": [{"ja": "もし痛かったら、すぐに教えてください。", "vi": "Nếu đau, vui lòng cho tôi biết ngay."},{"ja": "もし熱があったら、医者に行きます。", "vi": "Nếu có sốt, tôi sẽ đi gặp bác sĩ."}], "care_context": "患者さんに症状を報告するよう指示する時：「もし気分が悪かったら、すぐに言ってください」", "explanation": {"ja": "もし～たら は仮定的な状況を示します。もしかして～かもしれない、という意味です。", "vi": "もし～たら biểu hiện tình huống giả định. Có nghĩa là có thể~."}, "difficulty": "medium"}, {"pattern": "～ば、～", "meaning": {"ja": "条件的な結果。～したら～になる", "vi": "Kết quả điều kiện. Nếu ~ thì ~ xảy ra"}, "examples": [{"ja": "毎日運動すれば、健康になります。", "vi": "Nếu tập thể dục hàng ngày, bạn sẽ khỏe mạnh."},{"ja": "薬を飲めば、痛みが減ります。", "vi": "Nếu uống thuốc, cơn đau sẽ giảm."}], "care_context": "患者さんに健康的な行動の利点を説明する時：「毎日、散歩すれば、気分が良くなります」", "explanation": {"ja": "～ば は条件形です。「～したら」に似ていますが、より自然な文法です。", "vi": "～ば là dạng điều kiện. Giống \"～したら\" nhưng ngữ pháp tự nhiên hơn."}, "difficulty": "medium"}, {"pattern": "～ないと、～", "meaning": {"ja": "否定的な条件。～しなかったら、悪い結果になる", "vi": "Điều kiện phủ định. Nếu không ~ thì sẽ có kết quả xấu"}, "examples": [{"ja": "毎日薬を飲まないと、病気が悪くなります。", "vi": "Nếu không uống thuốc hàng ngày, bệnh sẽ trở nặng."},{"ja": "ちゃんと歯を磨かないと、虫歯になります。", "vi": "Nếu không đánh răng kỹ lưỡng, sẽ bị sâu răng."}], "care_context": "患者さんに重要な健康行動を説明する時：「毎日血圧を測らないと、危険です」", "explanation": {"ja": "～ないと は「～しなかったら」という意味で、必須の行動を強調します。", "vi": "～ないと có nghĩa là \"nếu không~\" và nhấn mạnh hành động cần thiết."}, "difficulty": "medium"}], "dialogue": ["患者さん: 「もし転んだら、どうしたらいいですか？」", "介護職: 「もし転んだら、すぐに私たちに言ってください。」", "患者さん: 「わかりました。」", "介護職: 「毎日運動すれば、とても健康になります。」", "患者さん: 「そうですね。毎日散歩しましょう。」", "介護職: 「はい。そして、薬を飲まないと、病気が悪くなります。」", "患者さん: 「わかりました。毎日薬を飲みます。」"], "key_phrases": [{"ja": "もし～たら", "vi": "Nếu ~"},{"ja": "～ば、～", "vi": "~nếu ~"},{"ja": "～ないと", "vi": "Nếu không ~"},{"ja": "もし転んだら", "vi": "Nếu ngã"}], "cultural_note": {"ja": "条件形を使うことで、患者さんに対して優しく指導することができます。強制的ではなく、論理的な結果を説明することで、患者さんの理解と協力を引き出します。", "vi": "Sử dụng dạng điều kiện cho phép hướng dẫn bệnh nhân một cách nhẹ nhàng. Bằng cách giải thích kết quả hợp lý thay vì ép buộc, bạn có thể lôi cuốn sự hiểu biết và hợp tác của bệnh nhân."}, "quiz": [{"question": {"ja": "「もし痛かったら」の意味は？", "vi": "Ý nghĩa của \"もし痛かったら\" là?"}, "options": [{"ja": "今、痛いです", "vi": "Bây giờ đau"},{"ja": "もしかして痛いかもしれない", "vi": "Có thể đau"},{"ja": "痛くありません", "vi": "Không đau"},{"ja": "昨日、痛かった", "vi": "Hôm qua đã đau"}], "correct_answer": 1, "explanation": {"ja": "もし～たら は仮定的な条件を表します。痛い可能性がある場合の指示です。", "vi": "もし～たら biểu hiện điều kiện giả định. Là chỉ dạn cho trường hợp có thể đau."}, "difficulty": "easy"}, {"question": {"ja": "「毎日運動すれば、健康になる」の意味は？", "vi": "Ý nghĩa của \"毎日運動すれば、健康になる\" là?"}, "options": [{"ja": "毎日運動することが義務である", "vi": "Tập thể dục hàng ngày là bắt buộc"},{"ja": "毎日運動すると、健康の結果が起こる", "vi": "Nếu tập thể dục hàng ngày, sức khỏe sẽ tốt lên"},{"ja": "毎日運動していない", "vi": "Không tập thể dục hàng ngày"},{"ja": "健康はすでに得られた", "vi": "Sức khỏe đã được đạt được"}], "correct_answer": 1, "explanation": {"ja": "～ば は条件形で、毎日運動すると健康になるという因果関係を示します。", "vi": "～ば là dạng điều kiện, biểu hiện mối quan hệ nhân quả giữa tập thể dục hàng ngày và sức khỏe tốt."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 3, 3, 'grammar', '{"intro": {"ja": "「ある」「いる」という存在を表す動詞を学びます。「患者さんはどこにいますか？」「お水はありますか？」など、物や人の位置や存在を説明する時に必要です。", "vi": "Học động từ biểu hiện sự tồn tại \"ある\" \"いる\". \"Bệnh nhân ở đâu?\" \"Có nước không?\"... Cần thiết để nói về vị trí hoặc sự tồn tại của vật hoặc người."}, "patterns": [{"pattern": "N1 は N2 に あります・います", "meaning": {"ja": "物や人の存在と場所を表す。あります（物）、います（人・動物）", "vi": "Biểu hiện sự tồn tại và vị trí của vật hoặc người. あります (vật), います (người, động vật)"}, "examples": [{"ja": "病院に看護師がいます。", "vi": "Có y tá ở bệnh viện."},{"ja": "薬棚に薬があります。", "vi": "Có thuốc ở tủ thuốc."}], "care_context": "患者さんや物の位置を説明する時：「患者さんはシャワー室にいます」「血圧計はどこにあります」", "explanation": {"ja": "い形動詞の場合は「います」、い形以外の動詞の場合は「あります」を使います。", "vi": "Với động từ nhóm い, sử dụng \"います\", với nhóm khác sử dụng \"あります\"."}, "difficulty": "easy"}, {"pattern": "N は に ～ あります・います", "meaning": {"ja": "特定の場所に存在する", "vi": "Tồn tại ở một địa điểm cụ thể"}, "examples": [{"ja": "水が机の上にあります。", "vi": "Nước ở trên bàn."},{"ja": "患者さんが病室にいます。", "vi": "Bệnh nhân ở phòng bệnh."}], "care_context": "介護施設内での物や人の場所を確認する時：「患者さんは庭にいます」「タオルは洗面台の近くにあります」", "explanation": {"ja": "「に」は場所を示す助詞です。存在する場所を明確に示します。", "vi": "\"に\" là trợ từ chỉ vị trí. Biểu hiện rõ ràng nơi tồn tại."}, "difficulty": "medium"}, {"pattern": "～が あります・います（存在の説明）", "meaning": {"ja": "ある物や人が存在することを強調する", "vi": "Nhấn mạnh sự tồn tại của vật hoặc người nào đó"}, "examples": [{"ja": "問題があります。", "vi": "Có vấn đề."},{"ja": "高齢患者さんがいます。", "vi": "Có bệnh nhân cao tuổi."}], "care_context": "患者さんの状態や問題を報告する時：「患者さんに痛みがあります」「転倒のリスクがあります」", "explanation": {"ja": "が を使う場合は、新しい情報や強調する内容を示します。ある・いるの場合は存在そのものを強調します。", "vi": "Khi sử dụng が, nó chỉ thông tin mới hoặc nội dung được nhấn mạnh. Đối với ある・いる, nó nhấn mạnh sự tồn tại."}, "difficulty": "medium"}], "dialogue": ["介護職A: 「患者さんはどこにいますか？」", "介護職B: 「患者さんは病室にいます。」", "介護職A: 「そうですか。薬棚に薬がありますか？」", "介護職B: 「はい、薬棚に薬があります。」", "介護職A: 「いいですね。何か問題がありますか？」", "介護職B: 「いいえ、問題がありません。」", "介護職A: 「わかりました。ありがとうございます。」"], "key_phrases": [{"ja": "～に います", "vi": "~ở"},{"ja": "～に あります", "vi": "~có/tồn tại"},{"ja": "どこに いますか", "vi": "~ở đâu"},{"ja": "どこに ありますか", "vi": "~ở đâu"}], "cultural_note": {"ja": "存在動詞「ある」「いる」を正確に使うことは、介護施設のコミュニケーションの基本です。患者さんの安全と管理のために、正確な位置情報と状態の報告は不可欠です。", "vi": "Sử dụng chính xác động từ tồn tại \"ある\" \"いる\" là cơ bản của giao tiếp tại cơ sở chăm sóc. Để đảm bảo an toàn bệnh nhân, báo cáo vị trí và tình trạng chính xác là cần thiết."}, "quiz": [{"question": {"ja": "「患者さんは病室にいます」の意味は？", "vi": "Ý nghĩa của \"患者さんは病室にいます\" là?"}, "options": [{"ja": "患者さんが病室を見ている", "vi": "Bệnh nhân đang nhìn phòng bệnh"},{"ja": "患者さんが病室にいる状態である", "vi": "Bệnh nhân ở trong phòng bệnh"},{"ja": "患者さんが病室を掃除している", "vi": "Bệnh nhân đang lau dọn phòng bệnh"},{"ja": "患者さんが病室を離れた", "vi": "Bệnh nhân rời khỏi phòng bệnh"}], "correct_answer": 1, "explanation": {"ja": "います は人が存在することを示します。患者さんが病室にいる状態を表します。", "vi": "います biểu hiện sự tồn tại của người. Nó chỉ trạng thái bệnh nhân ở trong phòng bệnh."}, "difficulty": "easy"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 4, 3, 'grammar', '{"intro": {"ja": "「ことができる」と「られ形」を使った能力表現を学びます。「患者さんは歩くことができます」「看護師さんは中国語が話せます」など、能力や可能性を説明する時に必要です。", "vi": "Học cách biểu hiện khả năng sử dụng \"ことができる\" và \"られ形\". \"Bệnh nhân có thể đi bộ\", \"Y tá có thể nói tiếng Trung\"... Cần thiết để giải thích khả năng hoặc khả năng xảy ra."}, "patterns": [{"pattern": "V ことができます", "meaning": {"ja": "能力：～することができる、～する可能性がある", "vi": "Khả năng: có thể làm~, khả năng làm~"}, "examples": [{"ja": "患者さんは歩くことができます。", "vi": "Bệnh nhân có thể đi bộ."},{"ja": "私は日本語を話すことができます。", "vi": "Tôi có thể nói tiếng Nhật."}], "care_context": "患者さんの能力や回復状況を説明する時：「患者さんは一人で食べることができます」「階段を登ることができません」", "explanation": {"ja": "ことができる は動詞の基本形と組み合わせて、能力や可能性を表します。", "vi": "ことができる kết hợp với dạng cơ bản của động từ để biểu hiện khả năng hoặc khả năng."}, "difficulty": "medium"}, {"pattern": "られ形・える形（受身・可能）", "meaning": {"ja": "られ形は可能を表す。～することができる", "vi": "Dạng られ biểu hiện khả năng. Có thể làm~"}, "examples": [{"ja": "これは食べられます。", "vi": "Cái này có thể ăn được."},{"ja": "日本語が話せます。", "vi": "Tôi có thể nói tiếng Nhật."}], "care_context": "患者さんの制限や能力を簡潔に説明する時：「患者さんは歩けます」「硬い物は食べられません」", "explanation": {"ja": "られ形は「～できる」という意味で、簡潔で自然な表現です。", "vi": "Dạng られ có nghĩa \"có thể~\" và là biểu hiện tự nhiên và ngắn gọn."}, "difficulty": "medium"}, {"pattern": "N は N ができます（能力の有無）", "meaning": {"ja": "特定の能力を持つ、持たない", "vi": "Có hoặc không có khả năng cụ thể"}, "examples": [{"ja": "患者さんは英語ができます。", "vi": "Bệnh nhân có thể nói tiếng Anh."},{"ja": "私は料理ができません。", "vi": "Tôi không thể nấu ăn."}], "care_context": "患者さんや同僚のスキルや能力を説明する時：「患者さんは書くことができます」「田中さんは中国語ができます」", "explanation": {"ja": "ができます は特定のスキルや技能を持つことを表します。", "vi": "ができます biểu hiện có kỹ năng hoặc tài năng cụ thể."}, "difficulty": "easy"}], "dialogue": ["患者さん: 「私はもう歩くことができますか？」", "看護師: 「はい、患者さんは歩くことができます。」", "患者さん: 「よかった。」", "看護師: 「でも、急いで歩かないでください。ゆっくり歩いてください。」", "患者さん: 「わかりました。」", "看護師: 「そして、階段は登れません。まだ危険です。」", "患者さん: 「理解しました。ゆっくり歩きます。」"], "key_phrases": [{"ja": "～ことができます", "vi": "Có thể~"},{"ja": "～られます", "vi": "Có thể~"},{"ja": "～ができます", "vi": "Có khả năng~"},{"ja": "～られません", "vi": "Không thể~"}], "cultural_note": {"ja": "患者さんの能力を正確に理解することは、安全なケアの計画に必要不可欠です。回復段階に応じて、できることとできないことを明確に区別することが、患者さんの尊厳と安全の両立を実現します。", "vi": "Hiểu chính xác khả năng của bệnh nhân là cần thiết để lập kế hoạch chăm sóc an toàn. Phân biệt rõ ràng những gì có thể và không thể làm theo giai đoạn phục hồi giúp duy trì cả nhân phẩm và sự an toàn của bệnh nhân."}, "quiz": [{"question": {"ja": "「患者さんは歩くことができます」の意味は？", "vi": "Ý nghĩa của \"患者さんは歩くことができます\" là?"}, "options": [{"ja": "患者さんが歩いている", "vi": "Bệnh nhân đang đi bộ"},{"ja": "患者さんが歩く能力を持っている", "vi": "Bệnh nhân có khả năng đi bộ"},{"ja": "患者さんが歩きたい", "vi": "Bệnh nhân muốn đi bộ"},{"ja": "患者さんが歩かなければならない", "vi": "Bệnh nhân phải đi bộ"}], "correct_answer": 1, "explanation": {"ja": "ことができます は能力や可能性を示します。患者さんが歩く能力を持つことを示します。", "vi": "ことができます biểu hiện khả năng hoặc khả năng. Nó chỉ bệnh nhân có khả năng đi bộ."}, "difficulty": "medium"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 5, 3, 'grammar', '{"intro": {"ja": "「好きです」「嫌いです」「～のほうが～」など、好みや比較を表す表現を学びます。患者さんの好みを理解し、より良いケアを提供する時に必要です。", "vi": "Học những biểu hiện về sở thích hoặc so sánh như \"好きです\" \"嫌いです\" \"~のほうが~\". Cần thiết để hiểu sở thích bệnh nhân và cung cấp chăm sóc tốt hơn."}, "patterns": [{"pattern": "N が 好きです・嫌いです", "meaning": {"ja": "好みを表す。～が好き、～が嫌い", "vi": "Biểu hiện sở thích. Thích~, không thích~"}, "examples": [{"ja": "私は野菜が好きです。", "vi": "Tôi thích rau."},{"ja": "患者さんは辛い食べ物が嫌いです。", "vi": "Bệnh nhân không thích đồ ăn cay."}], "care_context": "患者さんの食事の好みを確認する時：「患者さんはどんな食べ物が好きですか？」「甘い物が嫌いですか？」", "explanation": {"ja": "すきです・きらいです は好みを表します。は ではなく が を使うことが大切です。", "vi": "すきです・きらいです biểu hiện sở thích. Quan trọng là sử dụng が thay vì は."}, "difficulty": "easy"}, {"pattern": "N1 の ほうが N2 より ～", "meaning": {"ja": "比較：N1はN2より～である", "vi": "So sánh: N1 ~ hơn N2"}, "examples": [{"ja": "りんごのほうがみかんより甘いです。", "vi": "Táo ngọt hơn quýt."},{"ja": "朝のほうが夜より涼しいです。", "vi": "Sáng sớm lạnh hơn ban đêm."}], "care_context": "患者さんの好みを比較して確認する時：「甘い物のほうが辛い物より好きですか？」", "explanation": {"ja": "のほうが～より は二つの物を比較する時に使います。より は比較の基準を示します。", "vi": "のほうが～より được sử dụng khi so sánh hai vật. より chỉ tiêu chuẩn so sánh."}, "difficulty": "medium"}, {"pattern": "一番 ～", "meaning": {"ja": "最高：一番好き、一番嫌い", "vi": "Cực nhất: thích nhất, ghét nhất"}, "examples": [{"ja": "私は果物の中で、バナナが一番好きです。", "vi": "Trong các loại trái cây, tôi thích chuối nhất."},{"ja": "患者さんは色の中で、青が一番好きです。", "vi": "Trong các màu, bệnh nhân thích xanh nhất."}], "care_context": "患者さんの最も好きな物や嫌いな物を確認する時：「一番好きな食べ物は何ですか？」", "explanation": {"ja": "いちばん は最高級を表します。複数の中から一つを選ぶ時に使います。", "vi": "いちばん biểu hiện cấp cao nhất. Được sử dụng khi chọn một trong nhiều cái."}, "difficulty": "easy"}], "dialogue": ["患者さん: 「私の好きな食べ物について質問があります。」", "介護職: 「もちろんです。何が好きですか？」", "患者さん: 「果物が好きです。りんごのほうがみかんより好きです。」", "介護職: 「わかりました。果物の中で、一番好きな物は何ですか？」", "患者さん: 「バナナが一番好きです。」", "介護職: 「いいですね。朝食にバナナを用意しましょう。」", "患者さん: 「ありがとうございます。」"], "key_phrases": [{"ja": "～が好きです", "vi": "Thích~"},{"ja": "～が嫌いです", "vi": "Không thích~"},{"ja": "～のほうが～より", "vi": "~ hơn ~"},{"ja": "一番好きな", "vi": "Thích nhất"}], "cultural_note": {"ja": "患者さんの個人的な好みを理解することは、ケアの質を向上させるための重要なステップです。好みを尊重することで、患者さんの生活の質を高め、信頼関係を築くことができます。", "vi": "Hiểu sở thích cá nhân của bệnh nhân là bước quan trọng để cải thiện chất lượng chăm sóc. Tôn trọng sở thích có thể nâng cao chất lượng cuộc sống của bệnh nhân và xây dựng mối quan hệ tin tưởng."}, "quiz": [{"question": {"ja": "「私は野菜が好きです」の場合、何を好きですか？", "vi": "Trong \"私は野菜が好きです\", thích cái gì?"}, "options": [{"ja": "肉が好き", "vi": "Thích thịt"},{"ja": "野菜が好き", "vi": "Thích rau"},{"ja": "米が好き", "vi": "Thích cơm"},{"ja": "わかりません", "vi": "Không biết"}], "correct_answer": 1, "explanation": {"ja": "が は好みを表す助詞です。野菜が好きということです。", "vi": "が là trợ từ biểu hiện sở thích. Nghĩa là thích rau."}, "difficulty": "easy"}]}' );
INSERT INTO lessons (id, course_id, unit, lesson_number, type, content) VALUES
(gen_random_uuid(), (SELECT id FROM courses WHERE title->>'ja' = 'JLPT N5 基本文法' LIMIT 1), 6, 3, 'grammar', '{"intro": {"ja": "「～ほうがいいです」「～なければならない」など、義務や必要性を表す表現を学びます。患者さんに対して、医療上必要な行動を説明する時に重要です。", "vi": "Học những biểu hiện biểu thị nghĩa vụ hoặc tính cần thiết như \"～ほうがいいです\" \"～なければならない\". Quan trọng để giải thích cho bệnh nhân những hành động cần thiết về mặt y tế."}, "patterns": [{"pattern": "～ほうがいいです", "meaning": {"ja": "推奨：～した方が良い、～しなさい（丁寧）", "vi": "Khuyến cáo: tốt hơn nên ~, nên ~ (lịch sự)"}, "examples": [{"ja": "毎日散歩したほうがいいです。", "vi": "Tốt hơn nên đi bộ hàng ngày."},{"ja": "薬を飲んだほうがいいですよ。", "vi": "Tốt hơn nên uống thuốc."}], "care_context": "患者さんに健康的な行動をお勧めする時：「毎日運動したほうがいいです」「もっと水を飲んだほうがいいです」", "explanation": {"ja": "ほうがいい は柔らかい推奨を表します。強制的ではなく、助言の形です。", "vi": "ほうがいい biểu hiện khuyến cáo mềm mỏng. Nó là dạng lời khuyên, không bắt buộc."}, "difficulty": "medium"}, {"pattern": "～なければならない", "meaning": {"ja": "義務：～しなければならない、～する必要がある", "vi": "Nghĩa vụ: phải ~, cần ~"}, "examples": [{"ja": "毎日血圧を測らなければならない。", "vi": "Phải đo huyết áp hàng ngày."},{"ja": "薬を飲まなければならない。", "vi": "Phải uống thuốc."}], "care_context": "患者さんに医療上必須の行動を説明する時：「毎日薬を飲まなければなりません」「定期的に診察を受けなければなりません」", "explanation": {"ja": "なければならない は強い義務を表します。医療指示など、必須の行動を示します。", "vi": "なければならない biểu hiện nghĩa vụ mạnh mẽ. Nó chỉ các hành động cần thiết như chỉ định y tế."}, "difficulty": "hard"}, {"pattern": "～ません か？（勧誘）", "meaning": {"ja": "勧誘：一緒に～しませんか、～しましょう", "vi": "Lời mời: bạn có muốn cùng ~ không, hãy cùng ~"}, "examples": [{"ja": "一緒に散歩しませんか？", "vi": "Bạn có muốn đi bộ cùng tôi không?"},{"ja": "お茶を飲みませんか？", "vi": "Bạn có muốn uống trà không?"}], "care_context": "患者さんを活動に勧誘する時：「一緒に運動しませんか？」「散歩に行きませんか？」", "explanation": {"ja": "ませんか は丁寧な勧誘の形です。相手が参加するか決める選択肢を与えます。", "vi": "ませんか là dạng lời mời lịch sự. Nó cho lựa chọn để người khác quyết định có tham gia hay không."}, "difficulty": "medium"}], "dialogue": ["看護師: 「患者さん、毎日散歩したほうがいいですよ。」", "患者さん: 「そうですか？」", "看護師: 「はい。毎日散歩すれば、健康が良くなります。」", "患者さん: 「わかりました。」", "看護師: 「そして、毎日薬を飲まなければなりません。」", "患者さん: 「はい。毎日飲みます。」", "看護師: 「では、明日一緒に散歩しませんか？」", "患者さん: 「いいですね。明日、散歩に行きましょう。」"], "key_phrases": [{"ja": "～ほうがいいです", "vi": "Tốt hơn nên~"},{"ja": "～なければならない", "vi": "Phải~"},{"ja": "～ませんか", "vi": "Bạn có muốn~"},{"ja": "～ましょう", "vi": "Hãy cùng~"}], "cultural_note": {"ja": "患者さんに指示や提案を与える時、表現の選び方が重要です。強制的ではなく、患者さんの自主性を尊重しながら、医療上必要な行動を促進することが、良い患者-介護職関係を築く鍵です。", "vi": "Khi đưa ra chỉ dạn hoặc đề xuất cho bệnh nhân, cách chọn biểu hiện là quan trọng. Thúc đẩy hành động cần thiết về mặt y tế mà vẫn tôn trọng tính tự chủ của bệnh nhân mà không bắt buộc là chìa khóa để xây dựng mối quan hệ tốt giữa bệnh nhân và nhân viên chăm sóc."}, "quiz": [{"question": {"ja": "「散歩したほうがいいです」と「散歩しなければならない」の違いは？", "vi": "Sự khác biệt giữa \"散歩したほうがいいです\" và \"散歩しなければならない\" là gì?"}, "options": [{"ja": "違いがない", "vi": "Không có sự khác biệt"},{"ja": "前者は推奨で、後者は義務である", "vi": "Cái trước là lời khuyên, cái sau là bắt buộc"},{"ja": "前者は強く、後者は弱い", "vi": "Cái trước mạnh, cái sau yếu"},{"ja": "前者は過去で、後者は未来である", "vi": "Cái trước là quá khứ, cái sau là tương lai"}], "correct_answer": 1, "explanation": {"ja": "ほうがいい は柔らかい推奨、なければならない は強い義務を表します。", "vi": "ほうがいい biểu hiện lời khuyên mềm mỏng, なければならない biểu hiện bắt buộc mạnh mẽ."}, "difficulty": "hard"}]}' );
